/* 상태 변경과 동시에 현재 이용 중인 세션 ID(포인터)를 동기화 */
UPDATE cafe_table
SET
    status = #{status},
    current_session_id = #{sessionId}  WHERE id = #{id}

/* 세션을 비활성화하고 퇴실 시각을 현재로 업데이트 */
UPDATE table_session
SET
    is_active = FALSE,
    check_out_time = NOW()
WHERE id = #{sessionId}

